CREATE PROC [dbo].[CREATE_EXEMP] @FromDate datetime, @ToDate datetime AS IF OBJECT_ID('EXEMP','U') IS NOT NULL DROP TABLE EXEMP IF OBJECT_ID('EXEMP_Info','U') IS NOT NULL DROP TABLE EXEMP_Info CREATE TABLE EXEMP ([Description] decimal, [Nil Rated Supplies]decimal, [Exempted (other than nil rated/non GST supply )] decimal, [Non-GST supplies] decimal ) CREATE TABLE EXEMP_Info ( [Total Nil Rated Supplies]    decimal, [Total Exempted Supplies]  decimal, [Total Non-GST Supplies] decimal ) INSERT INTO EXEMP_Info VALUES(0,0,0) IF OBJECT_ID('EXEMP_Header','U') IS NULL CREATE TABLE EXEMP_Header ( [Summary For Nil rated, exempted and non GST outward supplies (8)] Char(1)) INSERT INTO InfoTable Values('EXEMP',2,'<<Default>>','EXEMP',9) 